export function buildVariantConfig(name = 'straight') {
  if (name === 'coil') return COIL_VARIANT;
  if (name === 'bar') return BAR_VARIANT;
  if (name === 'solenoid') return SOLENOID_VARIANT;
  return STRAIGHT_VARIANT;
}

